import React, { useEffect, useState } from "react";
import { useUser } from "@clerk/clerk-react";
import axios from "axios";
import "./OrdersPage.css"; // linked new css file

const OrdersPage = () => {
  const { user } = useUser();
  const [orders, setOrders] = useState([]);

  useEffect(() => {
    const fetchOrders = async () => {
      if (!user) return;
      try {
        const res = await axios.get(`http://localhost:5000/api/orders/user/${user.id}`);
        setOrders(res.data);
      } catch (err) {
        console.error(err);
      }
    };
    fetchOrders();
  }, [user]);

  const handleCancel = async (orderId) => {
    const reason = prompt("Please enter the reason for cancelling this order:");
    if (!reason || reason.trim() === "") {
      alert("Cancellation reason is required!");
      return;
    }
    try {
      await axios.put(`http://localhost:5000/api/orders/${orderId}/cancel`, { cancelReason: reason });
      setOrders((prev) =>
        prev.map((order) =>
          order._id === orderId
            ? { ...order, status: "Cancelled", cancelReason: reason, cancelDate: new Date().toLocaleString() }
            : order
        )
      );
      alert("✅ Order cancelled successfully!");
    } catch (err) {
      console.error(err);
      alert("Failed to cancel order.");
    }
  };

  return (
    <div className="orders-page">
      <h2 className="orders-title">My Orders</h2>

      {orders.length === 0 ? (
        <p className="no-orders">No orders found.</p>
      ) : (
        orders.map((order) => (
          <div key={order._id} className="order-card">
            <div className="order-left">
              <img
                src={order.items[0]?.image || "https://cdn-icons-png.flaticon.com/512/679/679720.png"}
                alt="product"
                className="order-img"
              />
              <div>
                <h3>{order.items[0]?.name} × {order.items[0]?.quantity}</h3>
                <p>Items: {order.items.length}</p>
              </div>
            </div>

            <div className="order-center">
              <h4>{order.name}</h4>
              <p>{order.address}</p>
              <p>{order.mobile}</p>
            </div>

            <div className="order-right">
              <p className="price">₹{order.total}</p>
              <p>Method: {order.payment || "COD"}</p>
              <p>Date: {new Date(order.date).toLocaleDateString()}</p>
              <p>
                Payment:{" "}
                <span className={order.status === "Cancelled" ? "cancelled" : "pending"}>
                  {order.status || "Pending"}
                </span>
              </p>
              {order.status !== "Cancelled" && (
                <button className="cancel-btn" onClick={() => handleCancel(order._id)}>
                  Cancel Order
                </button>
              )}
            </div>
          </div>
        ))
      )}
    </div>
  );
};

export default OrdersPage;
